1	/* ==========================================================================
2	   GEX/VEX Dashboard v2.1 — 4-Tier Color System
3	   ========================================================================== */
4	
5	@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;600;700&family=DM+Sans:wght@400;500;600;700&display=swap');
6	
7	:root {
8	    --bg-workspace:     #06090f;
9	    --bg-panel:         #0c1018;
10	    --bg-widget:        #0f1520;
11	    --bg-widget-header: #131a28;
12	    --bg-row:           #111927;
13	    --bg-row-alt:       #0d1422;
14	    --bg-thead:         #151e30;
15	    --bg-input:         #1a2238;
16	    --bg-modal:         #111827;
17	
18	    --text-primary:     #e2e8f0;
19	    --text-secondary:   #94a3b8;
20	    --text-muted:       #475569;
21	    --text-bright:      #f8fafc;
22	
23	    --border:           #1e293b;
24	    --border-strong:    #334155;
25	
26	    --accent-cyan:      #06b6d4;
27	    --accent-green:     #22c55e;
28	    --accent-red:       #ef4444;
29	    --accent-yellow:    #eab308;
30	    --accent-blue:      #3b82f6;
31	
32	    --font-mono:        'JetBrains Mono', 'Fira Code', monospace;
33	    --font-sans:        'DM Sans', system-ui, sans-serif;
34	
35	    --widget-min-w:     480px;
36	    --widget-min-h:     350px;
37	}
38	
39	* { margin: 0; padding: 0; box-sizing: border-box; }
40	html, body { height: 100%; overflow: hidden; }
41	body {
42	    font-family: var(--font-mono);
43	    background: var(--bg-workspace);
44	    color: var(--text-primary);
45	}
46	
47	/* --- Toolbar ------------------------------------------------------------ */
48	
49	.toolbar {
50	    display: flex;
51	    align-items: center;
52	    gap: 10px;
53	    height: 42px;
54	    padding: 0 14px;
55	    background: var(--bg-panel);
56	    border-bottom: 1px solid var(--border);
57	    flex-shrink: 0;
58	}
59	.toolbar__brand {
60	    font-family: var(--font-sans);
61	    font-weight: 700;
62	    font-size: 15px;
63	    color: var(--accent-cyan);
64	    letter-spacing: -0.3px;
65	    margin-right: 6px;
66	}
67	.toolbar__brand span { color: var(--text-muted); font-weight: 400; font-size: 12px; }
68	.toolbar__sep { width: 1px; height: 20px; background: var(--border); margin: 0 4px; }
69	.toolbar__spacer { flex: 1; }
70	.toolbar__api { font-size: 11px; color: var(--text-muted); font-variant-numeric: tabular-nums; }
71	
72	.btn {
73	    font-family: var(--font-mono);
74	    font-size: 12px;
75	    font-weight: 500;
76	    padding: 4px 12px;
77	    border: 1px solid var(--border);
78	    border-radius: 5px;
79	    background: var(--bg-input);
80	    color: var(--text-secondary);
81	    cursor: pointer;
82	    transition: all 0.12s;
83	    white-space: nowrap;
84	    display: inline-flex;
85	    align-items: center;
86	    gap: 5px;
87	}
88	.btn:hover { background: var(--bg-thead); color: var(--text-primary); border-color: var(--text-muted); }
89	
90	.btn-sm {
91	    font-family: var(--font-mono);
92	    font-size: 11px;
93	    padding: 3px 8px;
94	    border: 1px solid var(--border);
95	    border-radius: 4px;
96	    background: var(--bg-input);
97	    color: var(--text-secondary);
98	    cursor: pointer;
99	    transition: all 0.12s;
100	}
101	.btn-sm:hover { background: var(--bg-thead); color: var(--text-primary); }
102	
103	/* --- Workspace ---------------------------------------------------------- */
104	
105	.workspace {
106	    display: flex;
107	    flex-wrap: wrap;
108	    align-content: flex-start;
109	    gap: 8px;
110	    padding: 8px;
111	    height: calc(100vh - 42px);
112	    overflow: auto;
113	}
114	
115	/* --- Widget ------------------------------------------------------------- */
116	
117	.widget {
118	    display: flex;
119	    flex-direction: column;
120	    min-width: var(--widget-min-w);
121	    min-height: var(--widget-min-h);
122	    width: 700px;
123	    height: 560px;
124	    background: var(--bg-widget);
125	    border: 1px solid var(--border);
126	    border-radius: 8px;
127	    overflow: hidden;
128	    resize: both;
129	}
130	.widget:focus-within { border-color: var(--border-strong); }
131	
132	.widget__head {
133	    display: flex;
134	    align-items: center;
135	    gap: 8px;
136	    padding: 6px 10px;
137	    background: var(--bg-widget-header);
138	    border-bottom: 1px solid var(--border);
139	    flex-shrink: 0;
140	    min-height: 38px;
141	    flex-wrap: wrap;
142	}
143	
144	.widget__ticker-input {
145	    font-family: var(--font-mono);
146	    font-size: 13px;
147	    font-weight: 600;
148	    width: 72px;
149	    padding: 3px 7px;
150	    background: var(--bg-input);
151	    border: 1px solid var(--border);
152	    border-radius: 4px;
153	    color: var(--text-bright);
154	    text-transform: uppercase;
155	    outline: none;
156	}
157	.widget__ticker-input:focus { border-color: var(--accent-cyan); }
158	
159	.wquote { display: flex; align-items: center; gap: 6px; font-size: 12px; }
160	.wquote__sym { font-weight: 700; color: var(--text-bright); font-size: 13px; }
161	.wquote__dot {
162	    width: 6px; height: 6px; border-radius: 50%; background: var(--accent-green);
163	    animation: pulse-dot 2s infinite;
164	}
165	@keyframes pulse-dot { 0%,100%{opacity:1} 50%{opacity:0.3} }
166	.wquote__price { font-weight: 600; }
167	.wquote__chg { font-size: 11px; font-weight: 500; }
168	.wquote__chg.up   { color: var(--accent-green); }
169	.wquote__chg.down { color: var(--accent-red); }
170	
171	.mode-tabs { display: flex; gap: 1px; background: var(--bg-input); border-radius: 4px; padding: 1px; margin-left: 4px; }
172	.mode-tab {
173	    font-family: var(--font-mono); font-size: 11px; font-weight: 600;
174	    padding: 3px 10px; border: none; border-radius: 3px;
175	    background: transparent; color: var(--text-muted); cursor: pointer;
176	}
177	.mode-tab:hover { color: var(--text-secondary); }
178	.mode-tab.active { background: var(--accent-cyan); color: var(--bg-workspace); }
179	
180	.widget__spacer { flex: 1; }
181	
182	/* Data timestamp display */
183	.widget__fetched-at {
184	    font-size: 10px;
185	    color: var(--accent-cyan);
186	    font-variant-numeric: tabular-nums;
187	    opacity: 0.8;
188	    letter-spacing: 0.02em;
189	}
190	
191	/* Fetch-in-progress indicator (sits between timestamp and countdown) */
192	.widget__fetch-indicator {
193	    display: inline-flex;
194	    align-items: center;
195	    width: 16px;
196	    height: 16px;
197	    justify-content: center;
198	}
199	.spinner-sm {
200	    display: inline-block;
201	    width: 10px; height: 10px;
202	    border: 1.5px solid var(--border);
203	    border-top-color: var(--accent-cyan);
204	    border-radius: 50%;
205	    animation: spin 0.5s linear infinite;
206	}
207	.pending-dot {
208	    color: var(--accent-yellow);
209	    font-size: 10px;
210	    animation: pulse-dot 1s infinite;
211	}
212	
213	.widget__timer { font-size: 10px; color: var(--text-muted); font-variant-numeric: tabular-nums; }
214	.widget__close {
215	    font-size: 14px; line-height: 1; border: none; background: none;
216	    color: var(--text-muted); cursor: pointer; padding: 2px 4px; border-radius: 3px;
217	}
218	.widget__close:hover { color: var(--accent-red); background: rgba(239,68,68,0.1); }
219	
220	.widget__body { flex: 1; overflow: auto; position: relative; min-height: 0; }
221	
222	/* --- Heatmap ------------------------------------------------------------ */
223	
224	.heatmap { border-collapse: separate; border-spacing: 0; font-size: 12px; width: max-content; min-width: 100%; }
225	
226	.heatmap thead th {
227	    position: sticky; top: 0; z-index: 20;
228	    background: var(--bg-thead); color: var(--text-secondary);
229	    font-weight: 600; font-size: 11px;
230	    padding: 5px 6px; text-align: right;
231	    border-bottom: 2px solid var(--border);
232	    white-space: nowrap; user-select: none; min-width: 72px;
233	}
234	.heatmap thead th .col-resize {
235	    position: absolute; right: 0; top: 0; bottom: 0; width: 5px;
236	    cursor: col-resize; background: transparent; z-index: 25;
237	}
238	.heatmap thead th .col-resize:hover,
239	.heatmap thead th .col-resize.active { background: var(--accent-cyan); opacity: 0.5; }
240	
241	.heatmap thead th:first-child {
242	    position: sticky; left: 0; z-index: 30;
243	    text-align: left; min-width: 78px; width: 78px; background: var(--bg-thead);
244	}
245	.heatmap thead th:last-child {
246	    position: sticky; right: 0; z-index: 30;
247	    background: var(--bg-thead); border-left: 2px solid var(--border); min-width: 90px;
248	}
249	
250	.heatmap td {
251	    padding: 3px 6px; text-align: right; font-variant-numeric: tabular-nums;
252	    border-bottom: 1px solid rgba(30,41,59,0.35); white-space: nowrap; font-size: 11px;
253	}
254	.heatmap tbody td:first-child {
255	    position: sticky; left: 0; z-index: 10; background: inherit;
256	    text-align: left; font-weight: 600; color: var(--text-secondary);
257	    min-width: 78px; width: 78px;
258	}
259	.heatmap tbody td:last-child {
260	    position: sticky; right: 0; z-index: 10; background: inherit;
261	    border-left: 2px solid var(--border); font-weight: 600;
262	}
263	
264	.heatmap tbody tr:nth-child(odd) { background: var(--bg-row); }
265	.heatmap tbody tr:nth-child(even) { background: var(--bg-row-alt); }
266	.heatmap tbody tr:hover { filter: brightness(1.2); }
267	
268	.heatmap tr.row--current {
269	    background: rgba(148,163,184,0.09) !important;
270	    outline: 1px solid rgba(148,163,184,0.22); outline-offset: -1px;
271	}
272	.heatmap tr.row--current td:first-child { color: var(--text-bright); }
273	.heatmap tr.row--current td:first-child::after { content: ' ►'; color: var(--accent-cyan); font-size: 9px; }
274	
275	.heatmap tr.row--pin {
276	    background: rgba(234,179,8,0.10) !important;
277	    outline: 1px solid rgba(234,179,8,0.30); outline-offset: -1px;
278	}
279	
280	.heatmap tfoot td {
281	    position: sticky; bottom: 0; z-index: 20;
282	    background: var(--bg-thead); padding: 5px 6px;
283	    font-weight: 700; font-size: 11px; border-top: 2px solid var(--border);
284	}
285	.heatmap tfoot td:first-child { position: sticky; left: 0; z-index: 30; background: var(--bg-thead); }
286	.heatmap tfoot td:last-child  { position: sticky; right: 0; z-index: 30; background: var(--bg-thead); border-left: 2px solid var(--border); }
287	
288	/* --- Status ------------------------------------------------------------- */
289	
290	.status-msg {
291	    display: flex; align-items: center; justify-content: center;
292	    height: 100%; min-height: 200px; font-size: 13px; color: var(--text-muted);
293	}
294	.status-msg.error { color: var(--accent-red); }
295	.spinner {
296	    display: inline-block; width: 16px; height: 16px;
297	    border: 2px solid var(--border); border-top-color: var(--accent-cyan);
298	    border-radius: 50%; animation: spin 0.5s linear infinite; margin-right: 8px;
299	}
300	@keyframes spin { to { transform: rotate(360deg); } }
301	
302	/* --- Settings Modal ----------------------------------------------------- */
303	
304	.modal-overlay {
305	    display: none; position: fixed; inset: 0; z-index: 1000;
306	    background: rgba(0,0,0,0.6); backdrop-filter: blur(4px);
307	    align-items: center; justify-content: center;
308	}
309	.modal-overlay.open { display: flex; }
310	
311	.modal {
312	    background: var(--bg-modal); border: 1px solid var(--border-strong);
313	    border-radius: 10px; padding: 24px 28px; width: 520px; max-height: 85vh; overflow-y: auto;
314	}
315	.modal h2 {
316	    font-family: var(--font-sans); font-size: 16px; font-weight: 700;
317	    color: var(--text-bright); margin-bottom: 16px;
318	}
319	
320	.modal__section-title {
321	    font-family: var(--font-sans); font-size: 11px; font-weight: 600;
322	    text-transform: uppercase; letter-spacing: 0.06em;
323	    color: var(--text-muted); margin: 18px 0 10px;
324	    padding-bottom: 6px; border-bottom: 1px solid var(--border);
325	}
326	
327	/* Color tier row */
328	.tier-row {
329	    display: grid;
330	    grid-template-columns: 1fr 50px 50px;
331	    align-items: center;
332	    gap: 10px;
333	    margin-bottom: 10px;
334	    padding: 8px 10px;
335	    border-radius: 6px;
336	    background: var(--bg-input);
337	}
338	.tier-row__label {
339	    font-size: 12px;
340	    color: var(--text-primary);
341	}
342	.tier-row__sublabel {
343	    font-size: 10px;
344	    color: var(--text-muted);
345	    margin-top: 1px;
346	}
347	.tier-row__col-head {
348	    font-size: 10px;
349	    color: var(--text-muted);
350	    text-align: center;
351	    font-weight: 600;
352	    text-transform: uppercase;
353	    letter-spacing: 0.04em;
354	}
355	
356	.color-input {
357	    width: 40px; height: 26px;
358	    border: 1px solid var(--border); border-radius: 4px;
359	    background: var(--bg-widget); cursor: pointer; padding: 2px;
360	}
361	
362	/* Threshold slider row */
363	.modal__row {
364	    display: flex;
365	    align-items: center;
366	    justify-content: space-between;
367	    margin-bottom: 12px;
368	}
369	.modal__label { font-size: 12px; color: var(--text-secondary); }
370	.modal__range { width: 160px; accent-color: var(--accent-cyan); }
371	.modal__range-val {
372	    font-size: 11px; color: var(--text-muted); width: 40px;
373	    text-align: right; font-variant-numeric: tabular-nums;
374	}
375	
376	/* Preview bar */
377	.modal__preview {
378	    display: flex;
379	    gap: 2px;
380	    height: 32px;
381	    border-radius: 6px;
382	    overflow: hidden;
383	    margin-bottom: 6px;
384	    border: 1px solid var(--border);
385	}
386	.modal__preview-swatch { flex: 1; position: relative; }
387	.modal__preview-swatch span {
388	    position: absolute; bottom: 2px; left: 50%; transform: translateX(-50%);
389	    font-size: 8px; font-family: var(--font-mono); color: rgba(255,255,255,0.6);
390	    white-space: nowrap;
391	}
392	
393	.modal__preview-labels {
394	    display: flex;
395	    justify-content: space-between;
396	    font-size: 9px;
397	    color: var(--text-muted);
398	    margin-bottom: 14px;
399	    padding: 0 2px;
400	}
401	
402	.modal__actions {
403	    display: flex; justify-content: flex-end; gap: 8px;
404	    margin-top: 20px; padding-top: 14px; border-top: 1px solid var(--border);
405	}
