234	    function connectSSE(w) {
235	        if (w._sse) return;  // already connected
236	        const url = `/api/stream/${w.symbol}?mode=${w.mode}`;
237	        const es = new EventSource(url);
238	
239	        es.addEventListener("open", () => {
240	            w.sseConnected = true;
241	            // SSE is live — slow REST polling to a 5-minute safety fallback
242	            restartWidgetTimer(w);
243	            console.debug(`[SSE] Connected: ${url}`);
244	        });
245	
246	        es.onmessage = (e) => {
247	            try {
248	                handleSSEUpdate(w, JSON.parse(e.data));
249	            } catch {}
250	        };
251	
252	        es.onerror = () => {
253	            w.sseConnected = false;
254	            es.close();
255	            w._sse       = null;
256	            w._sseSymbol = null;
257	            w._sseMode   = null;
258	            // Resume normal REST polling interval
259	            restartWidgetTimer(w);
260	            console.warn(`[SSE] Dropped for ${w.symbol}/${w.mode} — falling back to REST polling`);
261	        };
262	
263	        w._sse = es;
264	    }
