503	    async function fetchWidgetData(w) {
504	        const indicator = w.el.querySelector(".widget__fetch-indicator");
505	        indicator.innerHTML = '<span class="spinner-sm"></span>';
506	
507	        try {
508	            const resp = await fetch(`/api/matrix/${w.symbol}?mode=${w.mode}`);
509	            const data = await resp.json();
510	
511	            if (resp.status === 202 || data.pending) {
512	                if (!w.hasTable) {
513	                    w.el.querySelector(".widget__body").innerHTML =
514	                        `<div class="status-msg"><span class="spinner"></span>${data.message || "Fetching..."}</div>`;
515	                }
516	                indicator.innerHTML = '<span class="pending-dot" title="Waiting for background data">●</span>';
517	
518	                if (!w._pendingRetry) {
519	                    w._pendingRetry = setTimeout(() => {
520	                        w._pendingRetry = null;
521	                        fetchWidgetData(w);
522	                    }, 2000);
523	                }
524	                return;
525	            }
526	
527	            if (w._pendingRetry) {
528	                clearTimeout(w._pendingRetry);
529	                w._pendingRetry = null;
530	            }
531	
532	            if (data.error) {
533	                if (!w.hasTable) {
534	                    w.el.querySelector(".widget__body").innerHTML =
535	                        `<div class="status-msg error">${data.error}</div>`;
536	                }
537	                indicator.innerHTML = "";
538	                return;
539	            }
540	
541	            // Only re-render if data is newer than last render (timestamp guard)
542	            const newTimestamp = data.fetched_at || null;
543	            if (newTimestamp && newTimestamp === w.lastFetchedAt && w.hasTable) {
544	                indicator.innerHTML = "";
545	                updateQuoteFromData(w, data);
546	                updateFetchedAtDisplay(w, newTimestamp);
547	                return;
548	            }
549	
550	            w.data = data;
551	            w.lastFetchedAt = newTimestamp;
552	
553	            renderQuoteChip(w, data.quote);
554	            renderHeatmap(w, data);
555	            updateFetchedAtDisplay(w, newTimestamp);
556	
557	            if (data.api_calls !== undefined) {
558	                globalApiCalls = data.api_calls;
559	                document.getElementById("global-api").textContent = `API calls: ${globalApiCalls}`;
560	            }
561	        } catch (err) {
562	            if (!w.hasTable) {
563	                w.el.querySelector(".widget__body").innerHTML =
564	                    `<div class="status-msg error">Error: ${err.message}</div>`;
565	            }
566	            console.error("Fetch error:", err);
567	        }
568	
569	        indicator.innerHTML = "";
570	    }
