816	    function updateSettingsPreview() {
817	        const preview = document.getElementById("color-preview");
818	        if (!preview) return;
819	        preview.innerHTML = "";
820	
821	        const formCS = {
822	            extremePosFill: document.getElementById("s-ext-pos-fill").value,
823	            mediumPosFill:  document.getElementById("s-med-pos-fill").value,
824	            mediumNegFill:  document.getElementById("s-med-neg-fill").value,
825	            extremeNegFill: document.getElementById("s-ext-neg-fill").value,
826	            neutralFill:    document.getElementById("s-neutral-fill").value,
827	            extremePosText: document.getElementById("s-ext-pos-text").value,
828	            mediumPosText:  document.getElementById("s-med-pos-text").value,
829	            mediumNegText:  document.getElementById("s-med-neg-text").value,
830	            extremeNegText: document.getElementById("s-ext-neg-text").value,
831	            neutralText:    document.getElementById("s-neutral-text").value,
832	            threshold:      parseInt(document.getElementById("s-threshold").value),
833	        };
834	
835	        const thr = formCS.threshold / 100;
836	        const steps = 15;
837	        const midIndex = Math.floor(steps / 2);
838	
839	        for (let i = 0; i < steps; i++) {
840	            const ratio    = (i / (steps - 1)) * 2 - 1;
841	            const absRatio = Math.abs(ratio);
842	            const swatch   = document.createElement("div");
843	            swatch.className = "modal__preview-swatch";
844	
845	            let fillColor, textColor;
846	            if (Math.abs(ratio) < 0.02) {
847	                fillColor = formCS.neutralFill; textColor = formCS.neutralText;
848	            } else if (ratio > 0) {
849	                if (absRatio >= thr) {
850	                    const t = thr < 1 ? Math.pow((absRatio - thr) / (1 - thr), 0.7) : 1;
851	                    fillColor = lerpColor(formCS.neutralFill, formCS.extremePosFill, t, 0.35 + t * 0.65);
852	                    textColor = formCS.extremePosText;
853	                } else {
854	                    const t = thr > 0 ? Math.pow(absRatio / thr, 0.7) : 1;
855	                    fillColor = lerpColor(formCS.neutralFill, formCS.mediumPosFill, t, 0.35 + t * 0.65);
856	                    textColor = formCS.mediumPosText;
857	                }
858	            } else {
859	                if (absRatio >= thr) {
860	                    const t = thr < 1 ? Math.pow((absRatio - thr) / (1 - thr), 0.7) : 1;
861	                    fillColor = lerpColor(formCS.neutralFill, formCS.extremeNegFill, t, 0.35 + t * 0.65);
862	                    textColor = formCS.extremeNegText;
863	                } else {
864	                    const t = thr > 0 ? Math.pow(absRatio / thr, 0.7) : 1;
865	                    fillColor = lerpColor(formCS.neutralFill, formCS.mediumNegFill, t, 0.35 + t * 0.65);
866	                    textColor = formCS.mediumNegText;
867	                }
868	            }
869	
870	            swatch.style.background = fillColor;
871	            const labelText = i === 0 ? "−Max" : i === midIndex ? "0" : i === steps - 1 ? "+Max" : "";
872	            if (labelText) {
873	                const sp = document.createElement("span");
874	                sp.textContent = labelText;
875	                sp.style.color = textColor;
876	                swatch.appendChild(sp);
877	            }
878	            preview.appendChild(swatch);
879	        }
880	    }
